import com.github.javaparser.ast.expr.SimpleName;
import com.github.javaparser.ast.expr.Name;
import com.github.javaparser.ast.expr.MethodReferenceExpr;
import com.github.javaparser.ast.expr.StringLiteralExpr;
import com.github.javaparser.ast.observer.AstObserver;
import com.github.javaparser.ast.observer.ObservableProperty;

/**
 * Test cases to reproduce the bug where String and Boxed types are compared using identity (==)
 * instead of .equals() in setter methods.
 */
public class test_string_equals_bug {

    static class TestObserver implements AstObserver {
        public boolean propertyChangeDetected = false;
        public String oldValue = null;
        public String newValue = null;

        @Override
        public void propertyChange(com.github.javaparser.ast.Node observedNode, ObservableProperty property, Object oldValue, Object newValue) {
            this.propertyChangeDetected = true;
            this.oldValue = (String) oldValue;
            this.newValue = (String) newValue;
            System.out.println("Property change detected: " + property + " from '" + oldValue + "' to '" + newValue + "'");
        }
    }

    public static void main(String[] args) {
        System.out.println("Testing String identity comparison bug...\n");

        boolean allTestsPassed = true;

        // Test 1: SimpleName with different String objects with same value
        System.out.println("Test 1: SimpleName.setIdentifier() with equal but not identical Strings");
        SimpleName simpleName = new SimpleName("test");
        TestObserver observer1 = new TestObserver();
        simpleName.register(observer1);

        String newIdentifier = new String("test"); // Same value, different object
        simpleName.setIdentifier(newIdentifier);

        if (!observer1.propertyChangeDetected) {
            System.out.println("❌ FAIL: Property change NOT detected for SimpleName (Bug confirmed!)");
            allTestsPassed = false;
        } else {
            System.out.println("✓ PASS: Property change detected for SimpleName");
        }
        System.out.println();

        // Test 2: Name with different String objects with same value
        System.out.println("Test 2: Name.setIdentifier() with equal but not identical Strings");
        Name name = new Name("example");
        TestObserver observer2 = new TestObserver();
        name.register(observer2);

        String newNameIdentifier = new String("example"); // Same value, different object
        name.setIdentifier(newNameIdentifier);

        if (!observer2.propertyChangeDetected) {
            System.out.println("❌ FAIL: Property change NOT detected for Name (Bug confirmed!)");
            allTestsPassed = false;
        } else {
            System.out.println("✓ PASS: Property change detected for Name");
        }
        System.out.println();

        // Test 3: LineComment with different String objects with same value
        System.out.println("Test 3: LineComment.setContent() with equal but not identical Strings");
        LineComment comment = new LineComment("original comment");
        TestObserver observer3 = new TestObserver();
        comment.register(observer3);

        String newContent = new String("original comment"); // Same value, different object
        comment.setContent(newContent);

        if (!observer3.propertyChangeDetected) {
            System.out.println("❌ FAIL: Property change NOT detected for Comment (Bug confirmed!)");
            allTestsPassed = false;
        } else {
            System.out.println("✓ PASS: Property change detected for Comment");
        }
        System.out.println();

        // Test 4: StringLiteralExpr with different String objects with same value
        System.out.println("Test 4: StringLiteralExpr.setValue() with equal but not identical Strings");
        StringLiteralExpr stringLiteral = new StringLiteralExpr("hello");
        TestObserver observer4 = new TestObserver();
        stringLiteral.register(observer4);

        String newStringValue = new String("hello"); // Same value, different object
        stringLiteral.setValue(newStringValue);

        if (!observer4.propertyChangeDetected) {
            System.out.println("❌ FAIL: Property change NOT detected for StringLiteralExpr (Bug confirmed!)");
            allTestsPassed = false;
        } else {
            System.out.println("✓ PASS: Property change detected for StringLiteralExpr");
        }
        System.out.println();

        // Test 5: MethodReferenceExpr with different String objects with same value
        System.out.println("Test 5: MethodReferenceExpr.setIdentifier() with equal but not identical Strings");
        MethodReferenceExpr methodRef = new MethodReferenceExpr();
        methodRef.setIdentifier("method");
        TestObserver observer5 = new TestObserver();
        methodRef.register(observer5);

        String newMethodIdentifier = new String("method"); // Same value, different object
        methodRef.setIdentifier(newMethodIdentifier);

        if (!observer5.propertyChangeDetected) {
            System.out.println("❌ FAIL: Property change NOT detected for MethodReferenceExpr (Bug confirmed!)");
            allTestsPassed = false;
        } else {
            System.out.println("✓ PASS: Property change detected for MethodReferenceExpr");
        }
        System.out.println();

        // Summary
        System.out.println("=".repeat(60));
        if (allTestsPassed) {
            System.out.println("✓ All tests PASSED - Bug is FIXED!");
            System.exit(0);
        } else {
            System.out.println("❌ Some tests FAILED - Bug still exists!");
            System.exit(1);
        }
    }
}

