import com.github.javaparser.ast.comments.LineComment;
import com.github.javaparser.ast.expr.SimpleName;
import com.github.javaparser.ast.expr.Name;
import com.github.javaparser.ast.expr.MethodReferenceExpr;
import com.github.javaparser.ast.expr.StringLiteralExpr;
import com.github.javaparser.ast.observer.AstObserver;
import com.github.javaparser.ast.observer.ObservableProperty;

/**
 * Test cases to reproduce the bug where String and Boxed types are compared using identity (==)
 * instead of .equals() in setter methods. This creates a problem when the setter is called with
 * a String object that has the same value but is a different instance.
 */
public class test_string_equals_bug2 {

    static class TestObserver implements AstObserver {
        public int propertyChangeCount = 0;

        @Override
        public void propertyChange(com.github.javaparser.ast.Node observedNode, ObservableProperty property, Object oldValue, Object newValue) {
            propertyChangeCount++;
            System.out.println("  -> Property change #" + propertyChangeCount + ": " + property + " from '" + oldValue + "' to '" + newValue + "'");
        }

        @Override
        public void parentChange(com.github.javaparser.ast.Node observedNode, com.github.javaparser.ast.Node previousParent, com.github.javaparser.ast.Node newParent) {
        }

        @Override
        public void listChange(com.github.javaparser.ast.NodeList<?> observedNode, ListChangeType type, int index, com.github.javaparser.ast.Node nodeAddedOrRemoved) {
        }

        @Override
        public void listReplacement(com.github.javaparser.ast.NodeList<?> observedNode, int index, com.github.javaparser.ast.Node oldNode, com.github.javaparser.ast.Node newNode) {
        }
    }

    public static void main(String[] args) {
        System.out.println("Testing String identity comparison bug - detailed analysis\n");

        boolean allTestsPassed = true;

        // Test 1: SimpleName - identity comparison issue
        System.out.println("Test 1: SimpleName.setIdentifier() - identity vs equals comparison");
        SimpleName simpleName = new SimpleName("test");

        // Get the current internal String instance
        String originalString = simpleName.getIdentifier();
        System.out.println("  Original string instance: " + System.identityHashCode(originalString));

        TestObserver observer1 = new TestObserver();
        simpleName.register(observer1);

        // Case A: Set with the SAME instance (should skip because it's actually the same)
        System.out.println("  Case A: Setting with SAME instance:");
        simpleName.setIdentifier(originalString);
        boolean caseA = (observer1.propertyChangeCount == 0);
        System.out.println("  Expected: No property change (same instance)");
        System.out.println("  Actual: " + (caseA ? "No property change ✓" : "Property change triggered ✗"));

        // Case B: Set with a DIFFERENT instance but same value
        observer1.propertyChangeCount = 0;
        String newIdentifier = new String("test"); // Different instance, same value
        System.out.println("  Case B: Setting with DIFFERENT instance but same value:");
        System.out.println("  New string instance: " + System.identityHashCode(newIdentifier));
        System.out.println("  Values equal: " + originalString.equals(newIdentifier));
        System.out.println("  References equal: " + (originalString == newIdentifier));

        simpleName.setIdentifier(newIdentifier);

        // With the bug: property change won't fire because == returns false (different instances)
        // After fix: property change should fire because values are equal
        System.out.println("  Expected after bug: Property change triggered (values are equal)");
        System.out.println("  Actual: " + (observer1.propertyChangeCount > 0 ? "Property change triggered" : "No property change (BUG!)"));

        // Check if the internal string was actually updated to the new instance
        String afterSet = simpleName.getIdentifier();
        System.out.println("  Internal string updated: " + (afterSet == newIdentifier ? "Yes ✓" : "No (BUG: still old instance)"));

        if (observer1.propertyChangeCount == 0) {
            System.out.println("  ❌ FAIL: Property change should have been triggered!");
            allTestsPassed = false;
        } else {
            System.out.println("  ✓ PASS");
        }
        System.out.println();

        // Test 2: The real issue - when using identity comparison, equal values are treated as different
        System.out.println("Test 2: Demonstrating the actual bug scenario");
        System.out.println("  Creating SimpleName with string literal 'hello'");
        SimpleName name1 = new SimpleName("hello");
        String str1 = name1.getIdentifier();

        System.out.println("  Creating a new String object with value 'hello'");
        String str2 = new String("hello");

        System.out.println("  str1.equals(str2): " + str1.equals(str2));
        System.out.println("  str1 == str2: " + (str1 == str2));
        System.out.println("  Identity hash str1: " + System.identityHashCode(str1));
        System.out.println("  Identity hash str2: " + System.identityHashCode(str2));

        TestObserver observer2 = new TestObserver();
        name1.register(observer2);

        System.out.println("  Calling setIdentifier(str2)...");
        name1.setIdentifier(str2);

        System.out.println("  Property changes triggered: " + observer2.propertyChangeCount);

        // The bug: If using ==, it will think the value changed and fire notification
        // Expected behavior with equals(): recognize they're equal and skip notification
        if (observer2.propertyChangeCount > 0) {
            System.out.println("  ❌ BUG CONFIRMED: Property change triggered even though values are equal!");
            System.out.println("     (This happens because the code uses == instead of .equals())");
            allTestsPassed = false;
        } else {
            System.out.println("  ✓ CORRECT: No property change (values are equal)");
        }
        System.out.println();

        // Summary
        System.out.println("=".repeat(70));
        if (!allTestsPassed) {
            System.out.println("❌ Bug confirmed: Identity comparison (==) causes issues with Strings");
            System.out.println("   Solution: Use Objects.equals() or .equals() for String comparisons");
            System.exit(1);
        } else {
            System.out.println("✓ All tests PASSED - Bug is FIXED!");
            System.exit(0);
        }
    }
}

