import com.github.javaparser.ast.comments.LineComment;
import com.github.javaparser.ast.expr.SimpleName;
import com.github.javaparser.ast.expr.Name;
import com.github.javaparser.ast.expr.MethodReferenceExpr;
import com.github.javaparser.ast.expr.StringLiteralExpr;
import com.github.javaparser.ast.observer.AstObserver;
import com.github.javaparser.ast.observer.ObservableProperty;

/**
 * Test to verify the fix for String identity comparison bug.
 * After fix: Use .equals() instead of == for String comparisons in setters.
 * Expected behavior: Property change should only fire when values are actually different.
 */
public class test_string_equals_fixed {

    static class TestObserver implements AstObserver {
        public int propertyChangeCount = 0;

        @Override
        public void propertyChange(com.github.javaparser.ast.Node observedNode, ObservableProperty property, Object oldValue, Object newValue) {
            propertyChangeCount++;
            System.out.println("  Property change #" + propertyChangeCount + ": " + property + " from '" + oldValue + "' to '" + newValue + "'");
        }

        @Override
        public void parentChange(com.github.javaparser.ast.Node observedNode, com.github.javaparser.ast.Node previousParent, com.github.javaparser.ast.Node newParent) {
        }

        @Override
        public void listChange(com.github.javaparser.ast.NodeList<?> observedNode, ListChangeType type, int index, com.github.javaparser.ast.Node nodeAddedOrRemoved) {
        }

        @Override
        public void listReplacement(com.github.javaparser.ast.NodeList<?> observedNode, int index, com.github.javaparser.ast.Node oldNode, com.github.javaparser.ast.Node newNode) {
        }
    }

    public static void main(String[] args) {
        System.out.println("Testing String equals() fix - Correct behavior validation\n");

        boolean allTestsPassed = true;

        // Test 1: SimpleName - should NOT fire when values are equal (different instances)
        System.out.println("Test 1: SimpleName.setIdentifier() with equal values (different instances)");
        SimpleName simpleName = new SimpleName("test");
        TestObserver observer1 = new TestObserver();
        simpleName.register(observer1);

        String newIdentifier = new String("test"); // Different instance, same value
        simpleName.setIdentifier(newIdentifier);

        if (observer1.propertyChangeCount == 0) {
            System.out.println("  ✓ PASS: No property change fired (values are equal)");
        } else {
            System.out.println("  ❌ FAIL: Property change fired even though values are equal!");
            allTestsPassed = false;
        }
        System.out.println();

        // Test 2: SimpleName - SHOULD fire when values are different
        System.out.println("Test 2: SimpleName.setIdentifier() with different values");
        SimpleName simpleName2 = new SimpleName("original");
        TestObserver observer2 = new TestObserver();
        simpleName2.register(observer2);

        simpleName2.setIdentifier("modified");

        if (observer2.propertyChangeCount == 1) {
            System.out.println("  ✓ PASS: Property change fired (values are different)");
        } else {
            System.out.println("  ❌ FAIL: Property change should have fired for different values!");
            allTestsPassed = false;
        }
        System.out.println();

        // Test 3: Name - should NOT fire when values are equal
        System.out.println("Test 3: Name.setIdentifier() with equal values");
        Name name = new Name("example");
        TestObserver observer3 = new TestObserver();
        name.register(observer3);

        String newNameIdentifier = new String("example");
        name.setIdentifier(newNameIdentifier);

        if (observer3.propertyChangeCount == 0) {
            System.out.println("  ✓ PASS: No property change fired (values are equal)");
        } else {
            System.out.println("  ❌ FAIL: Property change fired even though values are equal!");
            allTestsPassed = false;
        }
        System.out.println();

        // Test 4: Comment - should NOT fire when values are equal
        System.out.println("Test 4: Comment.setContent() with equal values");
        LineComment comment = new LineComment("my comment");
        TestObserver observer4 = new TestObserver();
        comment.register(observer4);

        String newContent = new String("my comment");
        comment.setContent(newContent);

        if (observer4.propertyChangeCount == 0) {
            System.out.println("  ✓ PASS: No property change fired (values are equal)");
        } else {
            System.out.println("  ❌ FAIL: Property change fired even though values are equal!");
            allTestsPassed = false;
        }
        System.out.println();

        // Test 5: StringLiteralExpr - should NOT fire when values are equal
        System.out.println("Test 5: StringLiteralExpr.setValue() with equal values");
        StringLiteralExpr stringLiteral = new StringLiteralExpr("hello");
        TestObserver observer5 = new TestObserver();
        stringLiteral.register(observer5);

        String newValue = new String("hello");
        stringLiteral.setValue(newValue);

        if (observer5.propertyChangeCount == 0) {
            System.out.println("  ✓ PASS: No property change fired (values are equal)");
        } else {
            System.out.println("  ❌ FAIL: Property change fired even though values are equal!");
            allTestsPassed = false;
        }
        System.out.println();

        // Test 6: MethodReferenceExpr - should NOT fire when values are equal
        System.out.println("Test 6: MethodReferenceExpr.setIdentifier() with equal values");
        MethodReferenceExpr methodRef = new MethodReferenceExpr();
        methodRef.setIdentifier("method");
        TestObserver observer6 = new TestObserver();
        methodRef.register(observer6);

        String newMethodId = new String("method");
        methodRef.setIdentifier(newMethodId);

        if (observer6.propertyChangeCount == 0) {
            System.out.println("  ✓ PASS: No property change fired (values are equal)");
        } else {
            System.out.println("  ❌ FAIL: Property change fired even though values are equal!");
            allTestsPassed = false;
        }
        System.out.println();

        // Summary
        System.out.println("=".repeat(70));
        if (allTestsPassed) {
            System.out.println("✓ All tests PASSED - Bug is FIXED!");
            System.out.println("  String values are now compared using .equals() instead of ==");
            System.out.println("  Property changes only fire when values actually differ");
            System.exit(0);
        } else {
            System.out.println("❌ Some tests FAILED - Fix incomplete!");
            System.exit(1);
        }
    }
}

